// frontend/src/components/Analytics.js
import React, { useState, useEffect } from 'react';
import { getPlaces, getPrediction } from '../services/api';

const CROWD_COLORS = { Low: '#1D9E75', Medium: '#d4a017', High: '#e53935' };
const CAT_ICONS    = { mall: '🛍️', cafe: '☕', gym: '💪', restaurant: '🍽️' };

export default function Analytics() {
  const [places, setPlaces]       = useState([]);
  const [predictions, setPred]    = useState({});
  const [loading, setLoading]     = useState(true);

  useEffect(() => {
    async function load() {
      setLoading(true);
      try {
        const data = await getPlaces('all', '');
        setPlaces(data);
        const entries = await Promise.all(
          data.map(p => getPrediction(p.id).then(pred => [p.id, pred]))
        );
        setPred(Object.fromEntries(entries));
      } finally {
        setLoading(false);
      }
    }
    load();
  }, []);

  if (loading) return (
    <div style={{ textAlign: 'center', padding: '60px', color: '#bbb' }}>
      <div style={{ fontSize: '36px', marginBottom: '12px' }}>📊</div>
      Loading analytics...
    </div>
  );

  // Compute summary stats from predictions
  const lowCount    = places.filter(p => predictions[p.id]?.crowd_level === 'Low').length;
  const medCount    = places.filter(p => predictions[p.id]?.crowd_level === 'Medium').length;
  const highCount   = places.filter(p => predictions[p.id]?.crowd_level === 'High').length;

  // Category crowd breakdown
  const catStats = {};
  places.forEach(p => {
    const cat  = p.category;
    const pred = predictions[p.id];
    if (!catStats[cat]) catStats[cat] = { total: 0, low: 0, medium: 0, high: 0 };
    catStats[cat].total++;
    if (pred?.crowd_level === 'Low')    catStats[cat].low++;
    if (pred?.crowd_level === 'Medium') catStats[cat].medium++;
    if (pred?.crowd_level === 'High')   catStats[cat].high++;
  });

  // Best places right now (Low crowd)
  const bestNow = places
    .filter(p => predictions[p.id]?.crowd_level === 'Low')
    .slice(0, 5);

  // Avoid now (High crowd)
  const avoidNow = places
    .filter(p => predictions[p.id]?.crowd_level === 'High')
    .slice(0, 5);

  const card = (children, extra = {}) => ({
    background: '#fff', borderRadius: '16px', padding: '20px',
    border: '1.5px solid #f0f0f0', ...extra,
  });

  return (
    <div>
      {/* Summary stats */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(150px, 1fr))', gap: '12px', marginBottom: '24px' }}>
        {[
          { label: 'Total Places',   value: places.length, icon: '📍', color: '#3a5bd9' },
          { label: 'Low Crowd Now',  value: lowCount,      icon: '✅', color: '#1D9E75' },
          { label: 'Medium Crowd',   value: medCount,      icon: '⚠️', color: '#d4a017' },
          { label: 'High Crowd Now', value: highCount,     icon: '🔴', color: '#e53935' },
        ].map(s => (
          <div key={s.label} style={{ ...card(), textAlign: 'center' }}>
            <div style={{ fontSize: '28px', marginBottom: '8px' }}>{s.icon}</div>
            <div style={{ fontSize: '26px', fontWeight: '800', color: s.color }}>{s.value}</div>
            <div style={{ fontSize: '11px', color: '#bbb', marginTop: '4px', textTransform: 'uppercase', letterSpacing: '0.5px' }}>{s.label}</div>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '24px' }}>
        {/* Best to visit now */}
        <div style={card()}>
          <h3 style={{ fontSize: '14px', fontWeight: '700', color: '#1a1a2e', margin: '0 0 14px', display: 'flex', alignItems: 'center', gap: '6px' }}>
            ✅ Best to Visit Now
          </h3>
          {bestNow.length === 0 ? (
            <p style={{ color: '#bbb', fontSize: '13px' }}>No low-crowd places right now</p>
          ) : bestNow.map(p => (
            <div key={p.id} style={{
              display: 'flex', justifyContent: 'space-between', alignItems: 'center',
              padding: '9px 0', borderBottom: '1px solid #f5f5f5',
            }}>
              <div>
                <div style={{ fontSize: '13px', fontWeight: '600', color: '#1a1a2e' }}>{p.name}</div>
                <div style={{ fontSize: '11px', color: '#bbb' }}>
                  {CAT_ICONS[p.category]} {predictions[p.id]?.waiting_time ?? 'N/A'}
                </div>
              </div>
              <span style={{
                background: '#e8f8f2', color: '#0f6e56',
                padding: '3px 10px', borderRadius: '20px', fontSize: '11px', fontWeight: '700',
              }}>Low</span>
            </div>
          ))}
        </div>

        {/* Avoid now */}
        <div style={card()}>
          <h3 style={{ fontSize: '14px', fontWeight: '700', color: '#1a1a2e', margin: '0 0 14px', display: 'flex', alignItems: 'center', gap: '6px' }}>
            🔴 Avoid Right Now
          </h3>
          {avoidNow.length === 0 ? (
            <p style={{ color: '#bbb', fontSize: '13px' }}>No high-crowd places right now</p>
          ) : avoidNow.map(p => (
            <div key={p.id} style={{
              display: 'flex', justifyContent: 'space-between', alignItems: 'center',
              padding: '9px 0', borderBottom: '1px solid #f5f5f5',
            }}>
              <div>
                <div style={{ fontSize: '13px', fontWeight: '600', color: '#1a1a2e' }}>{p.name}</div>
                <div style={{ fontSize: '11px', color: '#bbb' }}>
                  {CAT_ICONS[p.category]} {predictions[p.id]?.waiting_time ?? 'N/A'} wait
                </div>
              </div>
              <span style={{
                background: '#fdecea', color: '#c0392b',
                padding: '3px 10px', borderRadius: '20px', fontSize: '11px', fontWeight: '700',
              }}>High</span>
            </div>
          ))}
        </div>
      </div>

      {/* Category breakdown */}
      <div style={card({ marginBottom: '24px' })}>
        <h3 style={{ fontSize: '14px', fontWeight: '700', color: '#1a1a2e', margin: '0 0 16px' }}>
          Crowd by Category — Right Now
        </h3>
        {Object.entries(catStats).map(([cat, stat]) => (
          <div key={cat} style={{ marginBottom: '14px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '6px' }}>
              <span style={{ fontSize: '13px', fontWeight: '600', color: '#555' }}>
                {CAT_ICONS[cat] || '📍'} {cat.charAt(0).toUpperCase() + cat.slice(1)}
              </span>
              <span style={{ fontSize: '12px', color: '#aaa' }}>{stat.total} places</span>
            </div>
            {/* Stacked crowd bar */}
            <div style={{ height: '8px', background: '#f0f0f0', borderRadius: '6px', overflow: 'hidden', display: 'flex' }}>
              {[
                { val: stat.low,    color: '#1D9E75' },
                { val: stat.medium, color: '#d4a017' },
                { val: stat.high,   color: '#e53935' },
              ].map((s, i) => s.val > 0 && (
                <div key={i} style={{
                  height: '100%', background: s.color,
                  width: `${(s.val / stat.total) * 100}%`,
                  transition: 'width .5s ease',
                }} />
              ))}
            </div>
            <div style={{ display: 'flex', gap: '12px', marginTop: '5px' }}>
              {[
                { label: 'Low',    val: stat.low,    color: '#1D9E75' },
                { label: 'Medium', val: stat.medium, color: '#d4a017' },
                { label: 'High',   val: stat.high,   color: '#e53935' },
              ].map(s => (
                <span key={s.label} style={{ fontSize: '11px', color: s.color, fontWeight: '600' }}>
                  {s.label}: {s.val}
                </span>
              ))}
            </div>
          </div>
        ))}
      </div>

      {/* All places table */}
      <div style={card()}>
        <h3 style={{ fontSize: '14px', fontWeight: '700', color: '#1a1a2e', margin: '0 0 16px' }}>
          All Places — Current Predictions
        </h3>
        {places.map(p => {
          const pred   = predictions[p.id];
          const crowd  = pred?.crowd_level || 'Unknown';
          const colors = { Low: { bg: '#e8f8f2', text: '#0f6e56' }, Medium: { bg: '#fef8e8', text: '#7a4f00' }, High: { bg: '#fdecea', text: '#c0392b' } };
          const c      = colors[crowd] || { bg: '#f0f0f0', text: '#888' };
          return (
            <div key={p.id} style={{
              display: 'flex', justifyContent: 'space-between', alignItems: 'center',
              padding: '12px 0', borderBottom: '1px solid #f5f5f5',
            }}>
              <div>
                <div style={{ fontWeight: '600', fontSize: '14px', color: '#1a1a2e' }}>
                  {CAT_ICONS[p.category] || '📍'} {p.name}
                </div>
                <div style={{ fontSize: '12px', color: '#bbb', marginTop: '2px' }}>
                  Best time: {pred?.best_time ?? 'N/A'} · Wait: {pred?.waiting_time ?? 'N/A'}
                </div>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: '4px' }}>
                <span style={{
                  background: c.bg, color: c.text,
                  padding: '3px 12px', borderRadius: '20px',
                  fontSize: '12px', fontWeight: '700',
                }}>{crowd}</span>
                <span style={{ fontSize: '12px', color: '#1D9E75', fontWeight: '600' }}>
                  {pred?.estimated_cost ?? (p.avg_cost ? `₹${Math.round(p.avg_cost)}` : 'Free')}
                </span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
